"""ContentSpec — typed contract for every content artifact generated by OpenClaw.

Every content generator must accept a ContentSpec and every output must
carry the spec as front-matter metadata. The BrandGuard validates the spec
before generation begins.
"""
from __future__ import annotations

from dataclasses import dataclass, field
from typing import Any

ALLOWED_BRANDS = {"fulldigital", "cutmv"}


@dataclass
class ContentSpec:
    """Required header for all generated content."""

    brand: str
    offer_id: str
    angle_id: str
    voice_profile_id: str
    content_type: str  # "ad_script" | "landing_page" | "carousel" | "email" | "vsl_hook" | ...
    variant_id: str | None = None
    meta: dict[str, Any] = field(default_factory=dict)

    def to_dict(self) -> dict[str, Any]:
        d: dict[str, Any] = {
            "brand": self.brand,
            "offer_id": self.offer_id,
            "angle_id": self.angle_id,
            "voice_profile_id": self.voice_profile_id,
            "content_type": self.content_type,
        }
        if self.variant_id:
            d["variant_id"] = self.variant_id
        if self.meta:
            d["meta"] = self.meta
        return d
